// // This module implements a combinational logic circuit that sets output Y to HIGH (1) when either A1 or A2 is HIGH, and LOW (0) otherwise. It also handles the negated input B1_N in the default case.
module top_module(
    input A1,
    input A2,
    input B1_N,
    output reg Y
);always @* begin
    if (A1 && A2) begin
        Y = 1;
    end else if (A1 && !A2) begin
        Y = 0;
    end else if (!A1 && A2) begin
        Y = 0;
    end else begin
        Y = B1_N;
    end
end

endmodule
